// ============================================================
// BFS Contrôle — MODULE PDF (pdf.js)
// ============================================================
// Ce fichier contient TOUTE la génération de PDF de l'appli bureau.
// Il est chargé par index.html APRÈS le script principal.
// Il utilise les variables globales de index.html :
//   db, ME, $, fmt, fmtH, toast, clients, equipements, typesEquip,
//   contrats, pointsControle, loadBons
// Librairies requises (chargées dans index.html) : jsPDF + autoTable.
//
// ⚠️ Une erreur ici ne casse QUE les PDF, jamais la connexion ni le
// reste de l'appli. On peut donc modifier ce fichier sans risque.
// ============================================================

// Logo BFS (flamme) embarqué — utilisé en en-tête et filigrane du bon
const LOGO_BFS='data:image/png;base64,';

// ============================================================
// PDF — RAPPORT DE VÉRIFICATION
// ============================================================
async function exportVerifPDF(verifId){
  const {data:v}=await db.from('verifications').select('*,equipements(*,clients(*)),types_equipements(libelle,icone),agences(nom)').eq('id',verifId).single();
  const {data:res}=await db.from('resultats_controle').select('*').eq('verification_id',verifId).order('libelle_snapshot');
  if(!v){toast('Données introuvables','err');return}
  const {jsPDF}=window.jspdf;const doc=new jsPDF();
  const eq=v.equipements;const cl=eq?.clients;
  const raisonSocV='Bretagne Formation Sécurité';
  try{doc.addImage(LOGO_BFS,'PNG',12,5,16,16)}catch(e){}
  doc.setFontSize(20);doc.setFont('helvetica','bold');doc.setTextColor(50,50,50);doc.text('BFS',29,15);
  doc.setFontSize(7);doc.setTextColor(80);doc.setFont('helvetica','normal');doc.text(raisonSocV,29,19.5);
  doc.setFillColor(230,100,40);doc.rect(65,8,130,10,'F');
  doc.setTextColor(255);doc.setFont('helvetica','bold');doc.setFontSize(12);
  doc.text('RAPPORT DE VÉRIFICATION',130,15,{align:'center'});
  doc.setTextColor(0);doc.setFont('helvetica','normal');doc.setFontSize(9);
  doc.text(`${v.types_equipements?.libelle||''} — ${eq?.numero_identification||'—'} — Agence ${v.agences?.nom||'—'}`,14,26);
  doc.text(`Édité le ${new Date().toLocaleDateString('fr-FR')}`,160,26);
  doc.setTextColor(30);let y=32;
  doc.autoTable({startY:y,margin:{left:14,right:14},head:[],body:[
    ['Client',cl?.raison_sociale||'—'],['Adresse',`${cl?.adresse||''} ${cl?.code_postal||''} ${cl?.ville||''}`.trim()],
    ['N° identification',eq?.numero_identification||'—'],['Marque / Modèle',`${eq?.marque||'—'} ${eq?.modele||''}`],
    ['Localisation',`${eq?.localisation||'—'}${eq?.etage_zone?' / '+eq.etage_zone:''}`],
    ['Date vérification',fmt(v.date_verification)],['Prochaine échéance',fmt(v.date_prochaine_echeance)],
    ['Technicien',v.technicien||'—'],['Résultat global',v.resultat?.toUpperCase()||'—'],
  ],styles:{fontSize:10},columnStyles:{0:{fontStyle:'bold',cellWidth:50}},headStyles:{fillColor:[230,100,40]}});
  y=doc.lastAutoTable.finalY+8;
  if(res?.length){
    doc.autoTable({startY:y,margin:{left:14,right:14},head:[['Point de contrôle','Résultat']],
      body:res.map(r=>{let val='—';if(r.type_reponse==='oui_non')val=r.valeur_oui_non===true?'✓ OK':r.valeur_oui_non===false?'✗ NON':'—';else if(r.type_reponse==='numerique')val=r.valeur_numerique!=null?String(r.valeur_numerique):'—';else if(r.type_reponse==='texte')val=r.valeur_texte||'—';else if(r.type_reponse==='date')val=fmt(r.valeur_date);return[r.libelle_snapshot,val]}),
      styles:{fontSize:9},headStyles:{fillColor:[230,100,40]},
      didParseCell:(d)=>{if(d.column.index===1){if(d.cell.text[0]==='✓ OK')d.cell.styles.textColor=[22,163,74];if(d.cell.text[0]==='✗ NON')d.cell.styles.textColor=[220,38,38]}}
    });y=doc.lastAutoTable.finalY+8;
  }
  if(v.observations){doc.setFontSize(10);doc.text('Observations: '+v.observations.slice(0,150),14,y);y+=10}
  doc.save(`BFS_verif_${eq?.numero_identification||verifId}_${v.date_verification}.pdf`);toast('PDF généré');
}

// ============================================================
// PDF — CONTRAT
// ============================================================
async function exportContratPDF(id){
  const {data:c}=await db.from('contrats').select('*,clients(*),agences(nom,code)').eq('id',id).single();if(!c){toast('Contrat introuvable','err');return}
  const {jsPDF}=window.jspdf;const doc=new jsPDF();const cl=c.clients;
  const raisonSoc=c.agences?.code==='sevremont'?'Bocage Formation Sécurité':'Bretagne Formation Sécurité';
  // Filigrane flamme (sous le contenu)
  try{doc.saveGraphicsState();doc.setGState(new doc.GState({opacity:0.05}));doc.addImage(LOGO_BFS,'PNG',50,93,110,110);doc.restoreGraphicsState();}catch(e){}
  // En-tête charte BFS
  try{doc.addImage(LOGO_BFS,'PNG',12,5,16,16)}catch(e){}
  doc.setFontSize(20);doc.setFont('helvetica','bold');doc.setTextColor(50,50,50);doc.text('BFS',29,15);
  doc.setFontSize(7);doc.setTextColor(80);doc.setFont('helvetica','normal');doc.text(raisonSoc,29,19.5);
  doc.setFillColor(230,100,40);doc.rect(65,8,130,10,'F');
  doc.setTextColor(255);doc.setFont('helvetica','bold');doc.setFontSize(12);
  doc.text('CONTRAT DE MAINTENANCE INCENDIE',130,15,{align:'center'});
  doc.setTextColor(0);doc.setFont('helvetica','normal');doc.setFontSize(9);
  doc.text(`N° ${c.numero_contrat||'—'} — Agence ${c.agences?.nom||'—'}`,14,26);
  doc.text(`Édité le ${new Date().toLocaleDateString('fr-FR')}`,162,26);
  let y=31;
  doc.autoTable({startY:y,margin:{left:14,right:14},head:[],body:[['Prestataire','BFS — '+raisonSoc],['Client',cl?.raison_sociale||'—'],['Adresse',`${cl?.adresse||''} ${cl?.code_postal||''} ${cl?.ville||''}`.trim()||'—'],['SIRET',cl?.siret||'—'],['Contact',`${cl?.contact_nom||'—'}${cl?.contact_telephone?' — '+cl.contact_telephone:''}`],['Type de contrat',c.type_contrat],['Période',`${fmt(c.date_debut)} → ${fmt(c.date_fin)}`],['Périodicité des visites',c.periodicite_visite||'—']],styles:{fontSize:9.5},columnStyles:{0:{fontStyle:'bold',cellWidth:52}}});
  y=doc.lastAutoTable.finalY+7;
  // Chiffrage détaillé
  const lignes=Array.isArray(c.lignes)?c.lignes:[];
  if(lignes.length){
    doc.setFont('helvetica','bold');doc.setFontSize(10);doc.text('DÉTAIL DES ÉQUIPEMENTS SOUS CONTRAT',14,y);y+=3;
    const lib=code=>{const t=(typeof typesEquip!=='undefined'?typesEquip:[]).find(t=>t.code===code);return t?t.libelle:code};
    const total=lignes.reduce((s,l)=>s+(+l.quantite||0)*(+l.pu||0),0);
    const eur=n=>n.toLocaleString('fr-FR',{style:'currency',currency:'EUR'});
    doc.autoTable({startY:y,margin:{left:14,right:14},
      head:[['Équipement','Marque','Modèle','Qté','PU HT','Total HT']],
      body:[...lignes.map(l=>[lib(l.type),l.marque||'—',(l.modele||'—')+(l.resume?'\n'+l.resume:''),String(l.quantite),eur(+l.pu||0),eur((+l.quantite||0)*(+l.pu||0))]),
        [{content:'TOTAL HT',colSpan:5,styles:{fontStyle:'bold',halign:'right'}},{content:eur(total),styles:{fontStyle:'bold'}}]],
      styles:{fontSize:9},headStyles:{fillColor:[230,100,40]},
      columnStyles:{3:{halign:'center',cellWidth:14},4:{halign:'right',cellWidth:26},5:{halign:'right',cellWidth:28}}});
    y=doc.lastAutoTable.finalY+7;
  } else if(c.tarif_annuel){
    doc.setFont('helvetica','bold');doc.setFontSize(10);
    doc.text('Tarif annuel HT : '+c.tarif_annuel.toLocaleString('fr-FR',{style:'currency',currency:'EUR'}),14,y);y+=7;
  }
  // Avenants (ajouts / retraits signés)
  const avenants=Array.isArray(c.avenants)?c.avenants:[];
  avenants.forEach(av=>{
    if(y>230){doc.addPage();y=20}
    doc.setFont('helvetica','bold');doc.setFontSize(10);
    doc.text(`AVENANT N°${av.num} — ${fmt(av.date)}${av.signataire_nom?' — signé par '+av.signataire_nom:''}`,14,y);y+=3;
    const lib2=code=>{const t=(typeof typesEquip!=='undefined'?typesEquip:[]).find(t=>t.code===code);return t?t.libelle:code};
    const eur2=n=>n.toLocaleString('fr-FR',{style:'currency',currency:'EUR'});
    const deltaAv=(av.lignes||[]).reduce((s,l)=>s+(l.sens==='retrait'?-1:1)*(+l.quantite||0)*(+l.pu||0),0);
    doc.autoTable({startY:y,margin:{left:14,right:14},
      head:[['','Équipement','Marque / Modèle','Qté','PU HT','Total HT']],
      body:[...(av.lignes||[]).map(l=>[l.sens==='retrait'?'−':'+',lib2(l.type),[l.marque,l.modele].filter(Boolean).join(' ')+(l.resume?'\n'+l.resume:''),String(l.quantite),eur2(+l.pu||0),(l.sens==='retrait'?'−':'')+eur2((+l.quantite||0)*(+l.pu||0))]),
        [{content:'IMPACT ANNUEL HT',colSpan:5,styles:{fontStyle:'bold',halign:'right'}},{content:(deltaAv>=0?'+':'')+eur2(deltaAv),styles:{fontStyle:'bold'}}]],
      styles:{fontSize:8.5},headStyles:{fillColor:[230,100,40]},
      columnStyles:{0:{cellWidth:8,halign:'center',fontStyle:'bold'},3:{halign:'center',cellWidth:12},4:{halign:'right',cellWidth:24},5:{halign:'right',cellWidth:26}},
      didParseCell:(d)=>{if(d.section==='body'&&d.column.index===0){d.cell.styles.textColor=d.cell.text[0]==='−'?[220,38,38]:[22,163,74]}}});
    y=doc.lastAutoTable.finalY+3;
    if(av.signature_data){try{doc.addImage(av.signature_data,'PNG',150,y,40,12)}catch(e){}y+=14}
    y+=4;
  });
  if(c.notes){
    doc.setFont('helvetica','bolditalic');doc.setFontSize(8.5);doc.text('Conditions particulières :',14,y);
    doc.setFont('helvetica','normal');
    const nl=doc.splitTextToSize(c.notes,178);doc.text(nl,14,y+4.5);y+=4.5+nl.length*4+4;
  }
  // Signatures
  const sigY=Math.min(Math.max(y+6,235),255);
  doc.setDrawColor(150);doc.rect(14,sigY,85,32);doc.rect(110,sigY,82,32);
  doc.setFont('helvetica','normal');doc.setFontSize(8);
  doc.text('Signature du CLIENT (précédée de « Bon pour accord »)',14+42.5,sigY+4,{align:'center',maxWidth:80});
  doc.text('Pour '+raisonSoc,110+41,sigY+4,{align:'center'});
  if(c.signature_data){
    try{doc.addImage(c.signature_data,'PNG',22,sigY+8,68,18)}catch(e){}
    doc.setFontSize(8);doc.setFont('helvetica','bold');
    doc.text((c.signataire_nom||'')+(c.signe_le?' — signé le '+fmt(c.signe_le):''),14+42.5,sigY+30,{align:'center'});
  }
  doc.setFontSize(7);doc.setTextColor(150);
  doc.text('Généré le '+new Date().toLocaleString('fr-FR',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'}),105,290,{align:'center'});
  doc.save(`BFS_contrat_${c.numero_contrat||id}${c.signature_data?'_signe':''}.pdf`);toast('Contrat PDF généré');
}

// ============================================================
// PDF — BON D'INTERVENTION (régénération)
// ============================================================
async function regenererBon(bonId,sansConfirm){
  if(!sansConfirm&&!confirm("Êtes-vous sûr de vouloir régénérer ce bon d'intervention ?\nL'ancien PDF sera supprimé et remplacé.")) return;
  toast('Chargement des données…');

  // Récupérer le bon + infos session
  const {data:bon}=await db.from('bons_intervention').select('*').eq('id',bonId).single();
  if(!bon){toast('Bon introuvable','err');return}

  // Récupérer les infos client
  const {data:client}=await db.from('clients').select('*,agences(nom,code)').eq('id',bon.client_id).single();

  // Récupérer le technicien
  const {data:tech}=await db.from('profils').select('nom,prenom').eq('id',bon.technicien_id).single();
  const techNom=tech?`${tech.prenom||''} ${tech.nom}`.trim():'—';

  // Récupérer les vérifications de la session avec TOUS les champs équipement
  const {data:verifs}=await db.from('verifications')
    .select('*,equipements(numero_identification,localisation,marque,modele,capacite_valeur,capacite_unite,type_equipement_code,donnees_specifiques,types_equipements(libelle,icone))')
    .eq('session_id',bon.session_id)
    .order('created_at');

  if(!verifs||!verifs.length){toast('Aucune vérification trouvée pour cette session','err');return}

  // Récupérer le numéro de session
  const {data:sess}=await db.from('sessions_controle').select('numero').eq('id',bon.session_id).single();

  // Générer le PDF côté bureau avec jsPDF
  const {jsPDF}=window.jspdf;
  const doc=new jsPDF({unit:'mm',format:'a4'});
  // Filigrane flamme BFS (très léger, dessiné en premier pour rester sous le contenu)
  try{
    doc.saveGraphicsState();
    doc.setGState(new doc.GState({opacity:0.05}));
    doc.addImage(LOGO_BFS,'PNG',50,93,110,110);
    doc.restoreGraphicsState();
  }catch(e){/* filigrane non bloquant */}
  const dateStr=new Date(bon.date_intervention).toLocaleDateString('fr-FR');
  const numSession=sess?.numero||bon.numero_session||'—';
  const adresse=[client?.adresse,client?.code_postal,client?.ville].filter(Boolean).join(', ');

  // En-tête
  const raisonSocBFS = client?.agences?.code === 'sevremont' ? 'Bocage Formation Sécurité' : 'Bretagne Formation Sécurité';
  try{doc.addImage(LOGO_BFS,'PNG',12,5,16,16)}catch(e){}
  doc.setFontSize(20);doc.setFont('helvetica','bold');doc.setTextColor(50,50,50);doc.text('BFS',29,15);
  doc.setFontSize(7);doc.setTextColor(80);doc.setFont('helvetica','normal');doc.text(raisonSocBFS,29,19.5);
  doc.setFillColor(230,100,40);doc.rect(65,8,130,10,'F');
  doc.setTextColor(255);doc.setFont('helvetica','bold');doc.setFontSize(12);
  doc.text('BULLETIN D\'INTERVENTION INCENDIE',130,15,{align:'center'});
  doc.setTextColor(0);doc.setFont('helvetica','normal');doc.setFontSize(9);

  // Cases type intervention — alignées à droite
  const drawCB=(x,y,v)=>{doc.setDrawColor(0);doc.rect(x,y,3.5,3.5);if(v){doc.setFont('helvetica','bold');doc.setFontSize(8);doc.setTextColor(192,57,43);doc.text('X',x+0.5,y+3);doc.setTextColor(0);}};
  doc.setFont('helvetica','bold');doc.setFontSize(8.5);doc.text("Type d'intervention",155,27);
  doc.setFont('helvetica','normal');doc.setFontSize(8);
  drawCB(155,30,true);doc.text('Contrôle',160,33);drawCB(155,36,false);doc.text('Installation',160,39);

  // Matériel coché
  const mats=['Extincteur / RIA','Plan / Signalétique','BAES','Système de désenfumage','Alarme incendie'];
  const hasExt=verifs.some(v=>v.equipements?.type_equipement_code==='extincteur'||v.equipements?.type_equipement_code==='ria');
  let my=44;
  mats.forEach((m,i)=>{drawCB(155,my,i===0&&hasExt);doc.setFontSize(7.5);doc.text(m,160,my+3);my+=5;});

  // Infos intervention — adresse sur 2 lignes
  let y=31;
  doc.setFontSize(9);
  doc.text('Date de l\'intervention :',14,y);doc.setFont('helvetica','bold');doc.text(dateStr,65,y);
  y+=6;doc.setFont('helvetica','normal');doc.text('Nom du Client :',14,y);doc.setFont('helvetica','bold');doc.text(client?.raison_sociale||'—',65,y);
  y+=6;doc.setFont('helvetica','normal');doc.text('Lieu d\'intervention :',14,y);
  const adresseLines=doc.splitTextToSize(adresse||client?.ville||'—',85);
  doc.text(adresseLines,65,y);
  // Réserver 2 lignes pour l'adresse même si une seule
  y+=12;
  doc.text('N° bon :',14,y);doc.setFont('helvetica','bold');doc.setTextColor(192,57,43);doc.text(numSession,65,y);doc.setTextColor(0);
  y+=6;doc.setFont('helvetica','normal');doc.text('Technicien :',14,y);doc.text(techNom,65,y);

  // Tableau équipements
  // Colonnes : Désig=56, Cap=22, Loc=44, puis "TYPE DE VÉRIFICATION" = 5 sous-colonnes UNIFORMES de 12 mm
  y=Math.max(y+8,74);
  const cB={desig:14,cap:70,loc:92,tv:136,v1:136,v2:148,v3:160,v4:172,v5:184,end:196};

  // En-tête : ligne 1 — titres principaux
  doc.setFillColor(240,240,240);doc.rect(14,y,182,14,'F');
  doc.setDrawColor(180);doc.setFont('helvetica','bold');doc.setFontSize(7);
  doc.text('DÉSIGNATION',cB.desig+1,y+5);
  doc.text('TYPE/CAP.',cB.cap+1,y+5);
  doc.text('EMPLACEMENT',cB.loc+1,y+5);
  // Titre regroupé "TYPE DE VÉRIFICATION"
  doc.setFillColor(210,210,210);doc.rect(cB.tv,y,cB.end-cB.tv,14,'F');
  doc.setFontSize(7.5);doc.text('TYPE DE VÉRIFICATION',(cB.tv+cB.end)/2,y+5,{align:'center'});
  // Séparateurs principaux
  [cB.cap,cB.loc,cB.tv,cB.end].forEach(x=>doc.line(x,y,x,y+14));
  // Ligne de séparation entre titre et sous-colonnes
  doc.line(cB.tv,y+8,cB.end,y+8);
  // Sous-colonnes
  doc.setFontSize(5.8);
  [
    [cB.v1,'Vérif.'],[cB.v2,'MES'],[cB.v3,'MAA'],[cB.v4,'Réforme'],[cB.v5,'Interv.']
  ].forEach(([x,label])=>{
    doc.text(label,x+6,y+12.5,{align:'center'});
    doc.line(x,y+8,x,y+14);
  });
  doc.line(cB.end,y+8,cB.end,y+14);
  y+=14;

  // Lignes équipements (max 14, hauteur 7 pour avoir de la place)
  const rowH=7;const lignesMax=14;
  doc.setFont('helvetica','normal');doc.setFontSize(7.5);
  for(let idx=0;idx<lignesMax;idx++){
    const v=verifs[idx];
    doc.setDrawColor(200);doc.line(14,y,196,y);
    [cB.cap,cB.loc,cB.tv,cB.v2,cB.v3,cB.v4,cB.v5,cB.end].forEach(x=>doc.line(x,y,x,y+rowH));
    if(v){
      const eq=v.equipements;
      const agent=eq?.donnees_specifiques?.['ef-agent']||eq?.donnees_specifiques?.['e-agent']||'';
      const desig=`${idx+1} - ${eq?.types_equipements?.libelle||'—'}${agent?' '+agent:''}`;
      const cap=eq?.capacite_valeur?(eq.capacite_valeur+' '+(eq.capacite_unite||'')):'—';
      // Adresse emplacement sur 2 lignes si besoin
      const locLines=doc.splitTextToSize(eq?.localisation||'—',42);
      doc.text(desig.slice(0,38),cB.desig+1,y+4.5);
      doc.text(cap.slice(0,12),cB.cap+1,y+4.5);
      doc.text(locLines,cB.loc+1,y+(locLines.length>1?2.5:4.5));
      // Cocher la bonne colonne selon le palier
      const palierCode=v.palier_code||'';
      doc.setFont('helvetica','bold');doc.setTextColor(0,100,0);
      if(palierCode==='mise_en_service')doc.text('X',cB.v2+6,y+4.5,{align:'center'});
      else if(palierCode==='approfondie'||palierCode==='maa')doc.text('X',cB.v3+6,y+4.5,{align:'center'});
      else if(palierCode==='reforme'||palierCode==='revision')doc.text('X',cB.v4+6,y+4.5,{align:'center'});
      else if(palierCode==='intervention')doc.text('X',cB.v5+6,y+4.5,{align:'center'});
      else doc.text('X',cB.v1+6,y+4.5,{align:'center'}); // Vérification simple par défaut
      doc.setTextColor(0);doc.setFont('helvetica','normal');
    }
    y+=rowH;
  }
  doc.setDrawColor(200);doc.line(14,y,196,y);
  y+=1;doc.setFont('helvetica','bold');doc.setFontSize(8);
  doc.text('TOTAL',cB.loc+22,y+3.5,{align:'right'});
  doc.text(String(verifs.length),cB.v1+6,y+3.5,{align:'center'});
  y+=8;

  // Zone OUI/NON vide (à compléter manuellement si régénéré sans checklist)
  const reglItems=['Registre de sécurité signé','Plan d\'évacuation existant','Consignes de sécurité existantes','Panneaux extincteur existant','Boîtier d\'alarme incendie existant'];
  const startX=100;
  doc.rect(startX,y,96,reglItems.length*5+4);
  doc.setFillColor(230,230,230);doc.rect(startX+75,y,10,4,'F');doc.rect(startX+85,y,10,4,'F');
  doc.setFont('helvetica','bold');doc.setFontSize(7.5);doc.text('OUI',startX+80,y+3,{align:'center'});doc.text('NON',startX+90,y+3,{align:'center'});
  y+=4;
  reglItems.forEach((item,i)=>{
    doc.setFont('helvetica','normal');doc.text(item,startX+1,y+3.5);
    if(i<reglItems.length-1){doc.setDrawColor(200);doc.line(startX,y+5,startX+96,y+5);}
    y+=5;
  });
  y+=4;

  // Observations
  doc.setFont('helvetica','bolditalic');doc.setFontSize(8);doc.text('OBSERVATIONS :',14,y+4);
  doc.setFont('helvetica','normal');
  const obsText=verifs.map(v=>v.observations).filter(Boolean).join(' · ')||'—';
  const obsLines=doc.splitTextToSize(obsText,178);
  doc.text(obsLines,14,y+9);
  y+=9+obsLines.length*4+4;

  // Signatures
  const sigY=Math.max(y+6,250);
  doc.setDrawColor(150);doc.rect(14,sigY,85,28);doc.rect(110,sigY,82,28);
  doc.setFont('helvetica','normal');doc.setFontSize(8);
  doc.text('NOM, signature et cachet du CLIENT',14+42,sigY+4,{align:'center'});
  doc.text('NOM et signature du technicien',110+41,sigY+4,{align:'center'});
  if(bon.signature_data){try{doc.addImage(bon.signature_data,'PNG',18,sigY+6,76,18)}catch(e){}}
  if(bon.signataire_nom)doc.text(bon.signataire_nom,14+42,sigY+26,{align:'center'});
  if(bon.signature_tech_data){try{doc.addImage(bon.signature_tech_data,'PNG',113,sigY+6,74,18)}catch(e){}}
  doc.text(techNom,110+41,sigY+26,{align:'center'});
  doc.setFontSize(7);doc.setTextColor(150);const genTS=new Date().toLocaleString('fr-FR',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'});
  doc.text('Généré le '+genTS,105,290,{align:'center'});

  // Sauvegarder le PDF et archiver
  // ⚠️ RÈGLE : le PDF signé d'origine (généré sur le terrain) n'est JAMAIS
  // supprimé ni remplacé. Les bulletins régénérés sont archivés à part
  // sous le nom bulletin_<bonId>_<timestamp>.pdf.
  const nomFichier=`BFS_bon_${numSession}_${(client?.raison_sociale||'').replace(/[^a-zA-Z0-9]/g,'_')}.pdf`;
  doc.save(nomFichier);
  const pdfBlob=doc.output('blob');
  const {data:anciens}=await db.storage.from('bons-intervention').list('',{search:'bulletin_'+bonId});
  if(anciens&&anciens.length)await db.storage.from('bons-intervention').remove(anciens.map(f=>f.name));
  const fileName=`bulletin_${bonId}_${Date.now()}.pdf`;
  const {error:upErr}=await db.storage.from('bons-intervention').upload(fileName,pdfBlob,{contentType:'application/pdf'});
  if(!upErr){toast('Bulletin archivé ✓')}
  else{toast('Bulletin téléchargé localement (erreur Storage)','err')}
  loadBons();
}

// ============================================================
// PDF — RAPPORT COMPLET (détail par équipement)
// ============================================================
// Pour un bon donné : reprend toutes les vérifications de la session
// et détaille, équipement par équipement, chaque point de contrôle.
// Archivé dans Supabase Storage (comme le bulletin) + téléchargé.
async function rapportComplet(bonId){
  toast('Génération du rapport complet…');
  const {data:bon}=await db.from('bons_intervention').select('*').eq('id',bonId).single();
  if(!bon){toast('Bon introuvable','err');return}
  const {data:client}=await db.from('clients').select('*,agences(nom,code)').eq('id',bon.client_id).single();
  const {data:tech}=await db.from('profils').select('nom,prenom').eq('id',bon.technicien_id).single();
  const techNom=tech?`${tech.prenom||''} ${tech.nom}`.trim():'—';
  const {data:sess}=await db.from('sessions_controle').select('numero').eq('id',bon.session_id).single();
  const numSession=sess?.numero||bon.numero_session||'—';
  const {data:verifs}=await db.from('verifications')
    .select('*,equipements(numero_identification,localisation,etage_zone,marque,modele,capacite_valeur,capacite_unite,date_fabrication,date_mise_en_service,type_equipement_code,donnees_specifiques,types_equipements(libelle,icone))')
    .eq('session_id',bon.session_id).order('created_at');
  if(!verifs||!verifs.length){toast('Aucune vérification trouvée pour cette session','err');return}
  const {data:allRes}=await db.from('resultats_controle')
    .select('*').in('verification_id',verifs.map(v=>v.id)).order('libelle_snapshot');
  const resByVerif={};(allRes||[]).forEach(r=>{(resByVerif[r.verification_id]=resByVerif[r.verification_id]||[]).push(r)});

  const dateStr=new Date(bon.date_intervention).toLocaleDateString('fr-FR');
  const raisonSocBFS=client?.agences?.code==='sevremont'?'Bocage Formation Sécurité':'Bretagne Formation Sécurité';
  const {jsPDF}=window.jspdf;
  const doc=new jsPDF();

  // ---- En-tête : même charte graphique que le bulletin simple
  try{doc.addImage(LOGO_BFS,'PNG',12,5,16,16)}catch(e){}
  doc.setFontSize(20);doc.setFont('helvetica','bold');doc.setTextColor(50,50,50);doc.text('BFS',29,15);
  doc.setFontSize(7);doc.setTextColor(80);doc.setFont('helvetica','normal');doc.text(raisonSocBFS,29,19.5);
  doc.setFillColor(230,100,40);doc.rect(65,8,130,10,'F');
  doc.setTextColor(255);doc.setFont('helvetica','bold');doc.setFontSize(12);
  doc.text('BULLETIN D\'INTERVENTION DÉTAILLÉ',130,15,{align:'center'});
  doc.setTextColor(0);doc.setFont('helvetica','normal');doc.setFontSize(9);
  let y=31;
  doc.text('Date de l\'intervention :',14,y);doc.setFont('helvetica','bold');doc.text(dateStr,65,y);
  y+=6;doc.setFont('helvetica','normal');doc.text('Nom du Client :',14,y);doc.setFont('helvetica','bold');doc.text(client?.raison_sociale||'—',65,y);
  y+=6;doc.setFont('helvetica','normal');doc.text('Lieu d\'intervention :',14,y);
  doc.text(doc.splitTextToSize([client?.adresse,client?.code_postal,client?.ville].filter(Boolean).join(', ')||'—',85),65,y);
  y+=12;
  doc.text('N° bon :',14,y);doc.setFont('helvetica','bold');doc.setTextColor(192,57,43);doc.text(numSession,65,y);doc.setTextColor(0);
  y+=6;doc.setFont('helvetica','normal');doc.text('Technicien :',14,y);doc.text(techNom,65,y);
  y+=6;doc.text('Équipements vérifiés :',14,y);doc.setFont('helvetica','bold');doc.text(String(verifs.length),65,y);doc.setFont('helvetica','normal');
  y+=10;

  // ---- Détail par équipement
  const valRes=r=>{
    if(r.type_reponse==='oui_non')return r.valeur_oui_non===true?'✓ OK':r.valeur_oui_non===false?'✗ NON':'—';
    if(r.type_reponse==='numerique')return r.valeur_numerique!=null?String(r.valeur_numerique):'—';
    if(r.type_reponse==='texte')return r.valeur_texte||'—';
    if(r.type_reponse==='date')return fmt(r.valeur_date);
    return '—';
  };
  verifs.forEach((v,i)=>{
    const eq=v.equipements||{};
    if(y>235){doc.addPage();y=20}
    // Bandeau équipement
    doc.setFillColor(240,240,240);doc.rect(14,y,182,8,'F');
    doc.setFont('helvetica','bold');doc.setFontSize(10);doc.setTextColor(30);
    doc.text(`${i+1}. ${eq.types_equipements?.libelle||'Équipement'} — ${eq.numero_identification||'—'}`,16,y+5.5);
    const resTxt=(v.resultat||'—').toUpperCase();
    doc.setTextColor(v.resultat==='conforme'?22:v.resultat==='non conforme'?220:180,v.resultat==='conforme'?163:v.resultat==='non conforme'?38:120,v.resultat==='conforme'?74:38);
    doc.text(resTxt,194,y+5.5,{align:'right'});
    doc.setTextColor(30);y+=11;
    // Infos équipement
    doc.setFont('helvetica','normal');doc.setFontSize(8.5);
    const infos=[
      `Marque/Modèle : ${[eq.marque,eq.modele].filter(Boolean).join(' ')||'—'}`,
      eq.capacite_valeur?`Capacité : ${eq.capacite_valeur} ${eq.capacite_unite||''}`:null,
      `Emplacement : ${eq.localisation||'—'}${eq.etage_zone?' / '+eq.etage_zone:''}`,
      eq.date_fabrication?`Fabrication : ${fmt(eq.date_fabrication)}`:null,
      v.date_prochaine_echeance?`Prochaine échéance : ${fmt(v.date_prochaine_echeance)}`:null
    ].filter(Boolean).join('   ·   ');
    const infoLines=doc.splitTextToSize(infos,180);
    doc.text(infoLines,15,y);y+=infoLines.length*4+2;
    // Points de contrôle
    const res=resByVerif[v.id]||[];
    if(res.length){
      doc.autoTable({startY:y,margin:{left:14,right:14},
        head:[['Point de contrôle','Résultat']],
        body:res.map(r=>[r.libelle_snapshot,valRes(r)]),
        styles:{fontSize:8.5,cellPadding:1.5},headStyles:{fillColor:[230,100,40],fontSize:8.5},
        columnStyles:{1:{cellWidth:30,halign:'center'}},
        didParseCell:(d)=>{if(d.column.index===1){
          if(d.cell.text[0]==='✓ OK')d.cell.styles.textColor=[22,163,74];
          if(d.cell.text[0]==='✗ NON')d.cell.styles.textColor=[220,38,38];
        }}
      });
      y=doc.lastAutoTable.finalY+3;
    } else {
      doc.setFontSize(8.5);doc.setTextColor(120);doc.text('Aucun point de contrôle enregistré.',15,y);doc.setTextColor(30);y+=6;
    }
    if(v.observations){
      if(y>265){doc.addPage();y=20}
      doc.setFont('helvetica','bolditalic');doc.setFontSize(8.5);doc.text('Observations :',15,y);
      doc.setFont('helvetica','normal');
      const ol=doc.splitTextToSize(v.observations,155);doc.text(ol,42,y);y+=ol.length*4+3;
    }
    y+=4;
  });

  // ---- Filigrane + pied de page sur toutes les pages
  const nb=doc.getNumberOfPages();
  for(let p=1;p<=nb;p++){
    doc.setPage(p);
    try{
      doc.saveGraphicsState();
      doc.setGState(new doc.GState({opacity:0.04}));
      doc.addImage(LOGO_BFS,'PNG',50,93,110,110);
      doc.restoreGraphicsState();
    }catch(e){}
    doc.setFontSize(7);doc.setTextColor(150);
    doc.text(`${raisonSocBFS} — Bulletin détaillé ${numSession} — Page ${p}/${nb}`,105,292,{align:'center'});
    doc.setTextColor(30);
  }

  // ---- Téléchargement + archivage Storage
  const nomFichier=`BFS_bulletin_detaille_${numSession}_${(client?.raison_sociale||'').replace(/[^a-zA-Z0-9]/g,'_')}.pdf`;
  doc.save(nomFichier);
  const pdfBlob=doc.output('blob');
  // Supprimer les anciens rapports de ce bon, puis uploader le nouveau
  const {data:anciens}=await db.storage.from('bons-intervention').list('',{search:'rapport_'+bonId});
  if(anciens&&anciens.length)await db.storage.from('bons-intervention').remove(anciens.map(f=>f.name));
  const fileName=`rapport_${bonId}_${Date.now()}.pdf`;
  const {error:upErr}=await db.storage.from('bons-intervention').upload(fileName,pdfBlob,{contentType:'application/pdf'});
  if(!upErr){toast('Rapport complet archivé ✓')}
  else{toast('Rapport téléchargé localement (erreur Storage)','err')}
  loadBons();
}

// ============================================================
// ACTUALISER — régénère les DEUX bulletins d'un bon en un clic
// ============================================================
async function actualiserBon(bonId){
  if(!confirm("Régénérer le bulletin simple ET le bulletin détaillé ?\nLes anciens PDF seront remplacés."))return;
  await regenererBon(bonId,true);
  await rapportComplet(bonId);
}

// ============================================================
// PDF — RAPPORT D'INVENTAIRE DE STOCK
// ============================================================
async function rapportInventairePDF(invId){
  const {data:inv}=await db.from('stock_inventaires').select('*,profils(nom,prenom),agences(nom)').eq('id',invId).single();
  if(!inv){toast('Inventaire introuvable','err');return}
  const {data:mvts}=await db.from('stock_mouvements').select('*,stock_pieces(code,designation,marque,modele)').eq('inventaire_id',invId).order('created_at');
  const {jsPDF}=window.jspdf;const doc=new jsPDF();
  const raisonSoc='Bretagne Formation Sécurité';
  try{doc.saveGraphicsState();doc.setGState(new doc.GState({opacity:0.05}));doc.addImage(LOGO_BFS,'PNG',50,93,110,110);doc.restoreGraphicsState();}catch(e){}
  try{doc.addImage(LOGO_BFS,'PNG',12,5,16,16)}catch(e){}
  doc.setFontSize(20);doc.setFont('helvetica','bold');doc.setTextColor(50,50,50);doc.text('BFS',29,15);
  doc.setFontSize(7);doc.setTextColor(80);doc.setFont('helvetica','normal');doc.text(raisonSoc,29,19.5);
  doc.setFillColor(230,100,40);doc.rect(65,8,130,10,'F');
  doc.setTextColor(255);doc.setFont('helvetica','bold');doc.setFontSize(12);
  doc.text('RAPPORT D\'INVENTAIRE DE STOCK',130,15,{align:'center'});
  doc.setTextColor(0);doc.setFont('helvetica','normal');doc.setFontSize(9);
  const par=inv.profils?`${inv.profils.prenom||''} ${inv.profils.nom}`.trim():'—';
  doc.text(`Agence ${inv.agences?.nom||'—'} — démarré le ${new Date(inv.demarre_le).toLocaleString('fr-FR')} par ${par}`,14,26);
  doc.text(inv.termine_le?`Terminé le ${new Date(inv.termine_le).toLocaleString('fr-FR')}`:'⏳ En cours',150,26);
  let y=33;
  const lst=mvts||[];
  if(!lst.length){doc.setFontSize(11);doc.text('Aucune pièce comptée dans cet inventaire.',14,y+6);}
  else{
    const entrees=lst.filter(m=>(+m.delta)>0),rectifs=lst.filter(m=>(+m.delta)<0),conformes=lst.filter(m=>(+m.delta)===0);
    // Synthèse
    doc.autoTable({startY:y,margin:{left:14,right:14},head:[],body:[
      ['Pièces comptées',String(lst.length)],
      ['➕ Entrées (stock réel > théorique)',entrees.length+' pièce(s), +'+entrees.reduce((s,m)=>s+(+m.delta),0)],
      ['✎ Rectifications (stock réel < théorique)',rectifs.length+' pièce(s), '+rectifs.reduce((s,m)=>s+(+m.delta),0)],
      ['✓ Conformes (aucun écart)',String(conformes.length)],
    ],styles:{fontSize:10},columnStyles:{0:{fontStyle:'bold',cellWidth:95}}});
    y=doc.lastAutoTable.finalY+8;
    doc.setFont('helvetica','bold');doc.setFontSize(10);doc.text('DÉTAIL DES COMPTAGES',14,y);y+=3;
    doc.autoTable({startY:y,margin:{left:14,right:14},
      head:[['Code','Désignation','Théorique','Compté','Écart','Constat']],
      body:lst.map(m=>[m.stock_pieces?.code||'—',m.stock_pieces?.designation||'—',String(m.quantite_avant),String(m.quantite_apres),((+m.delta)>0?'+':'')+m.delta,(+m.delta)>0?'Entrée':(+m.delta)<0?'Rectification':'Conforme']),
      styles:{fontSize:8.5,cellPadding:1.5},headStyles:{fillColor:[230,100,40]},
      columnStyles:{2:{halign:'center'},3:{halign:'center'},4:{halign:'center',fontStyle:'bold'},5:{halign:'center'}},
      didParseCell:(d)=>{if(d.section==='body'&&(d.column.index===4||d.column.index===5)){
        const delta=parseFloat(d.row.raw[4]);
        if(delta>0)d.cell.styles.textColor=[22,163,74];
        else if(delta<0)d.cell.styles.textColor=[220,38,38];
        else d.cell.styles.textColor=[120,120,120];
      }}});
  }
  const nb=doc.getNumberOfPages();
  for(let p=1;p<=nb;p++){doc.setPage(p);doc.setFontSize(7);doc.setTextColor(150);
    doc.text(`${raisonSoc} — Inventaire du ${new Date(inv.demarre_le).toLocaleDateString('fr-FR')} — Page ${p}/${nb}`,105,292,{align:'center'});doc.setTextColor(30);}
  doc.save(`BFS_inventaire_${new Date(inv.demarre_le).toISOString().slice(0,10)}.pdf`);toast('Rapport généré');
}

console.log('✓ pdf.js chargé');
